import { ReactNode } from "react";
import {
  ParsedField,
  ParsedSchema,
  Renderable,
  FieldConfig as BaseFieldConfig,
  SchemaProvider,
} from "@acp-autoform/core";

// Field binding contract
// Normalized shape every form-library adapter must return from useField().

export interface FieldBinding {
  value: any;
  onChange: (...event: any[]) => void;
  onBlur: () => void;
  name: string;
  /** ref is optional - not all adapters provide one */
  ref?: React.Ref<any>;
}

export interface UseFieldReturn {
  field: FieldBinding;
}

export type UseFieldFn = (opts: { name: string }) => UseFieldReturn;

// AutoForm props

export interface AutoFormProps<T extends Record<string, any> = Record<string, any>> {
  /** Schema adapter that manages fields, default values, and validation. */
  schema: SchemaProvider<T>;
  /**
   * External form control handle. For react-hook-form: the return of createFormControl().
   * For TanStack: the form instance returned by the adapter's useAppForm() in a parent.
   */
  formControl?: any;
  /**
   * Runs after successful validation. Receives the values and submit event.
   * @default () => {}
   */
  onSubmit?: (
    values: T,
    form: any,
    e?: React.BaseSyntheticEvent,
  ) => void | Promise<void>;
  /**
   * Initial values merged over schema defaults.
   * @default inferred from schema
   */
  defaultValues?: Partial<T>;
  /** Controlled values that keep the form in sync with external state. */
  values?: Partial<T>;
  /** Extra UI rendered after the generated fields. */
  children?: ReactNode;
  /** Layout/wrapper components for fields, errors, and structure. */
  uiComponents: AutoFormUIComponents;
  /** Form components mapped to field types (string, number, select, etc.). */
  formComponents: AutoFormFieldComponents;
  /**
   * Show a default submit button after all fields.
   * @default false
   */
  withSubmit?: boolean;
  /**
   * Legacy hook to access the form instance after init.
   * @deprecated Prefer passing an external form control via `formControl`.
   */
  onFormInit?: (form: any) => void;
  /**
   * Props forwarded to the underlying <form> element.
   * @default {}
   */
  formProps?: React.ComponentProps<"form"> | Record<string, any>;
}

export type ExtendableAutoFormProps<T extends Record<string, any>> = Omit<
  AutoFormProps<T>,
  "uiComponents" | "formComponents"
> & {
  uiComponents?: Partial<AutoFormUIComponents>;
  formComponents?: Partial<AutoFormFieldComponents>;
};

// UI component contracts

export interface AutoFormUIComponents {
  /** Root form element. */
  Form: React.ComponentType<React.ComponentProps<"form">>;
  /** Wraps each field with label, error, and layout UI. */
  FieldWrapper: React.ComponentType<FieldWrapperProps>;
  /** Renders AutoForm configuration errors. */
  ErrorMessage: React.ComponentType<{ error: string }>;
  /** Submit button rendered when withSubmit is enabled. */
  SubmitButton: React.ComponentType<{ children: ReactNode }>;
  /** Wraps nested object fields. */
  ObjectWrapper: React.ComponentType<ObjectWrapperProps>;
  /** Wraps array fields and owns the add-item action. */
  ArrayWrapper: React.ComponentType<ArrayWrapperProps>;
  /** Wraps one array item and owns the remove-item action. */
  ArrayElementWrapper: React.ComponentType<ArrayElementWrapperProps>;
}

export interface AutoFormFieldComponents {
  [key: string]: React.ComponentType<AutoFormFieldProps>;
}

// Wrapper prop types

export interface FieldWrapperProps {
  label: Renderable<ReactNode>;
  error?: Renderable<ReactNode>;
  children: ReactNode;
  id: string;
  parsedField: ParsedField;
}

export interface ArrayWrapperProps {
  label: Renderable<ReactNode>;
  error?: Renderable<ReactNode>;
  children: ReactNode;
  inputProps: any;
  parsedField: ParsedField;
  onAddItem: () => void;
}

export interface ArrayElementWrapperProps {
  children: ReactNode;
  onRemove: () => void;
  index: number;
}

export interface ObjectWrapperProps {
  label: Renderable<ReactNode>;
  children: ReactNode;
  parsedField: ParsedField;
}

// Field component props

export interface AutoFormFieldProps {
  path: string[];
  id: string;
  error?: string;
  parsedField: ParsedField;
  label: Renderable<ReactNode>;
  inputProps: any;
}

// Context type

export interface AutoFormContextType {
  schema: ParsedSchema;
  uiComponents: AutoFormUIComponents;
  formComponents: AutoFormFieldComponents;
  /** The useField implementation injected by the active form library adapter. */
  useField: UseFieldFn;
}

// FieldConfig

export type FieldConfig<
  FieldTypes = string,
  CustomData = Record<string, any>,
> = BaseFieldConfig<
  ReactNode,
  FieldTypes,
  React.ComponentType<FieldWrapperProps>,
  CustomData
>;

// Re-exports

export type { SchemaProvider, ParsedField, ParsedSchema } from "@acp-autoform/core";

import { createContext, useContext } from "react";
import { AutoFormContextType, UseFieldReturn } from "./types";

const AutoFormContext = createContext<AutoFormContextType | null>(null);

export const AutoFormProvider = AutoFormContext.Provider;

export function useAutoForm() {
  const context = useContext(AutoFormContext);
  if (!context) {
    throw new Error("useAutoForm must be used within an AutoFormProvider");
  }
  return context;
}

/**
 * Context-delegating useField hook.
 * UI components call this. The actual implementation is injected by whichever
 * form library adapter (./react-hook-form or ./tanstack-form) wraps the tree.
 */
export function useField(opts: { name: string }): UseFieldReturn {
  const { useField: impl } = useAutoForm();
  return impl(opts);
}

import type { ParsedField } from "@acp-autoform/core";

export function getArrayItemDefaultValue(parsedField: ParsedField): any {
  const itemType = parsedField.schema?.[0]?.type;
  if (itemType === "object") return {};
  if (itemType === "array") return [];
  return null;
}

"use client";

// Shared adapter-agnostic root. Runtime form implementations live only in
// ./react-hook-form and ./tanstack-form so consumers can bundle one adapter.
export * from "./types";
export * from "./context";

"use client";

export * from "./AutoForm";
export * from "./AutoFormField";
export * from "./ArrayField";
export * from "./ObjectField";
export * from "./form-context";
export * from "./utils";
// Re-export shared root for convenience
export * from "../types";
export * from "../context";

import React, { useEffect, useMemo } from "react";
import { formOptions } from "@tanstack/react-form";
import {
  getDefaultValues,
  parseSchema,
  replaceEmptyValue,
} from "@acp-autoform/core";
import type { ParsedSchema } from "@acp-autoform/core";
import type { AutoFormProps } from "../types";
import { AutoFormProvider } from "../context";
import { AutoFormField } from "./AutoFormField";
import {
  getAppForm,
  preventPropagation,
  focusFirstInvalidInput,
} from "./utils";
import { useAppForm } from "./form-context";
import { useFieldTanStack, useSyncValues } from "./hooks";

export function AutoForm<T extends Record<string, any> = Record<string, any>>({
  formControl,
  schema,
  onSubmit = () => {},
  values,
  defaultValues,
  children,
  uiComponents,
  formComponents,
  withSubmit = false,
  onFormInit,
  formProps = {},
}: AutoFormProps<T>) {
  const parsedSchema: ParsedSchema = useMemo(
    () => parseSchema(schema),
    [schema],
  );
  const validator = useMemo(() => schema.getSchema?.(), [schema]);
  const { ref: _ref, ...restFormProps } =
    formProps as React.ComponentProps<"form">;

  const options = useMemo(
    () =>
      formOptions({
        ...(validator ? { validators: { onChange: validator as any } } : {}),
        defaultValues: {
          ...(getDefaultValues(schema) as Partial<T>),
          ...defaultValues,
        } as T,
        onSubmit: async ({ value, formApi }: { value: T; formApi: any }) => {
          const validation = schema.validateSchema(replaceEmptyValue(value));
          if (validation.success) {
            await onSubmit(validation.data, formApi);
          }
        },
        onSubmitInvalid: () => {
          focusFirstInvalidInput();
        },
      }),
    [defaultValues, onSubmit, schema, validator],
  );

  const internalForm = useAppForm(options);
  const form = formControl
    ? (formControl as typeof internalForm)
    : internalForm;

  useSyncValues(form, values);

  useEffect(() => {
    if (formControl) {
      (formControl as typeof internalForm).update(options);
    }
  }, [formControl, options]);

  useEffect(() => {
    onFormInit?.(form);
  }, [form, onFormInit]);

  const AppForm = getAppForm(form);

  return (
    <AppForm>
      <AutoFormProvider
        value={{
          schema: parsedSchema,
          uiComponents,
          formComponents,
          useField: useFieldTanStack,
        }}
      >
        <uiComponents.Form
          onSubmit={preventPropagation(() => {
            void form.handleSubmit();
          })}
          ref={_ref}
          {...restFormProps}
        >
          {parsedSchema.fields.map((field) => (
            <AutoFormField
              key={field.key}
              parsedField={field}
              path={[field.key]}
            />
          ))}
          {withSubmit && (
            <uiComponents.SubmitButton>Submit</uiComponents.SubmitButton>
          )}
          {children}
        </uiComponents.Form>
      </AutoFormProvider>
    </AppForm>
  );
}

import React from "react";
import { getLabel } from "@acp-autoform/core";
import type { ParsedField } from "@acp-autoform/core";
import type { AutoFormFieldProps } from "../types";
import { useAutoForm } from "../context";
import { ArrayField } from "./ArrayField";
import { ObjectField } from "./ObjectField";
import { useFormContext } from "./form-context";
import { formatTanStackPath, getErrorMessage } from "./utils";

export const AutoFormField: React.FC<{
  parsedField: ParsedField;
  path: string[];
}> = ({ path, parsedField }) => {
  const { formComponents, uiComponents } = useAutoForm();
  const form = useFormContext() as any;

  const domPath = path.join(".");
  const fullPath = formatTanStackPath(path);
  const fieldConfig = parsedField.fieldConfig;
  const FieldWrapper = fieldConfig?.fieldWrapper || uiComponents.FieldWrapper;
  const fieldProps = {
    name: fullPath as any,
    mode: parsedField.type === "array" ? "array" : undefined,
  };

  let FieldComponent: React.ComponentType<AutoFormFieldProps>;
  if (parsedField.type === "array") {
    FieldComponent = ArrayField;
  } else if (parsedField.type === "object") {
    FieldComponent = ObjectField;
  } else if (parsedField.type in formComponents) {
    FieldComponent = formComponents[parsedField.type]!;
  } else if ("fallback" in formComponents) {
    FieldComponent = formComponents.fallback;
  } else {
    FieldComponent = () => (
      <uiComponents.ErrorMessage
        error={`[AutoForm Configuration Error] No component found for type "${parsedField.type}" nor a fallback`}
      />
    );
  }

  const AppField = form.AppField as React.ComponentType<any>;
  return (
    <AppField {...fieldProps}>
      {(fieldApi: any) => {
        const error = getErrorMessage(fieldApi);

        return (
          <FieldWrapper
            label={getLabel(parsedField)}
            error={error}
            id={domPath}
            parsedField={parsedField}
          >
            <FieldComponent
              key={`${domPath}-input`}
              path={path}
              id={domPath}
              error={error}
              parsedField={parsedField}
              label={getLabel(parsedField)}
              inputProps={{
                ...fieldConfig?.inputProps,
                "aria-invalid": !!error || undefined,
              }}
            />
          </FieldWrapper>
        );
      }}
    </AppField>
  );
};

import React from "react";
import { getLabel } from "@acp-autoform/core";
import type { ParsedField } from "@acp-autoform/core";
import { useAutoForm } from "../context";
import { AutoFormField } from "./AutoFormField";
import { useFieldContext } from "./form-context";
import { getArrayItemDefaultValue } from "../utils";

export const ArrayField: React.FC<{
  id: string;
  path: string[];
  inputProps: any;
  parsedField: ParsedField;
  error?: string;
}> = ({ id, path, inputProps, error, parsedField }) => {
  const { uiComponents } = useAutoForm();
  const field = useFieldContext() as any;
  const defaultValue = getArrayItemDefaultValue(parsedField);

  return (
    <uiComponents.ArrayWrapper
      error={error}
      parsedField={parsedField}
      inputProps={{ key: `${id}-input`, ...inputProps }}
      label={getLabel(parsedField)}
      onAddItem={() => field.pushValue(defaultValue)}
    >
      {field.state.value?.map((_item: any, index: number) => (
        <uiComponents.ArrayElementWrapper
          key={index}
          onRemove={() => field.removeValue(index)}
          index={index}
        >
          <AutoFormField
            parsedField={parsedField.schema![0]!}
            path={[...path, index.toString()]}
          />
        </uiComponents.ArrayElementWrapper>
      ))}
    </uiComponents.ArrayWrapper>
  );
};

import React from "react";
import { getLabel } from "@acp-autoform/core";
import type { ParsedField } from "@acp-autoform/core";
import { useAutoForm } from "../context";
import { AutoFormField } from "./AutoFormField";

export const ObjectField: React.FC<{
  parsedField: ParsedField;
  path: string[];
}> = ({ path, parsedField }) => {
  const { uiComponents } = useAutoForm();

  return (
    <uiComponents.ObjectWrapper
      label={getLabel(parsedField)}
      parsedField={parsedField}
    >
      {Object.entries(parsedField.schema!).map(([_key, subField]) => {
        const sf = subField as ParsedField;
        return (
          <AutoFormField
            key={`${path.join(".")}.${sf.key}`}
            parsedField={sf}
            path={[...path, sf.key]}
          />
        );
      })}
    </uiComponents.ObjectWrapper>
  );
};

import { createFormHook, createFormHookContexts } from "@tanstack/react-form";

export const { fieldContext, useFieldContext, formContext, useFormContext } =
  createFormHookContexts();

export const { useAppForm } = createFormHook({
  fieldContext,
  formContext,
  fieldComponents: {},
  formComponents: {},
});

import { useEffect } from "react";
import type { UseFieldFn } from "../types";
import { useFieldContext } from "./form-context";

export const useFieldTanStack: UseFieldFn = () => {
  const fieldApi = useFieldContext();

  return {
    field: {
      value: fieldApi.state.value,
      onChange: (valueOrEvent: any) => {
        const target = valueOrEvent?.target;
        fieldApi.handleChange(
          target
            ? target.type === "checkbox"
              ? target.checked
              : target.value
            : valueOrEvent,
        );
      },
      onBlur: () => fieldApi.handleBlur(),
      name: String(fieldApi.name).replace(/\[(\d+)\]/g, ".$1"),
    },
  };
};

export function useSyncValues(
  form: { setFieldValue: (field: any, value: any, opts?: any) => void },
  values?: Record<string, any>,
) {
  useEffect(() => {
    if (!values) return;

    for (const [key, value] of Object.entries(values)) {
      form.setFieldValue(key, value, { dontUpdateMeta: true });
    }
  }, [form, values]);
}

import React from "react";

/**
 * Focus the first input element marked as invalid.
 * AutoFormField auto-injects aria-invalid into inputProps.
 */
export function focusFirstInvalidInput(): void {
  setTimeout(() => {
    // Find the first element marked as invalid natively or via our data attribute
    // Using a combined selector ensures we find the first one in document order
    const firstInvalid = document.querySelector<HTMLElement>(
      '[aria-invalid="true"]',
    );

    if (!firstInvalid) return;

    // If the element itself is directly focusable, focus it
    if (
      firstInvalid.tagName === "INPUT" ||
      firstInvalid.tagName === "SELECT" ||
      firstInvalid.tagName === "TEXTAREA" ||
      firstInvalid.tagName === "BUTTON" ||
      firstInvalid.hasAttribute("tabindex")
    ) {
      firstInvalid.focus();
      return;
    }

    // Otherwise, it's a wrapper (like MUI or Mantine), find the first focusable input inside it
    const input = firstInvalid.querySelector<HTMLElement>(
      'input, button, select, textarea, [tabindex]:not([tabindex="-1"])',
    );
    if (input) {
      input.focus();
    } else {
      firstInvalid.scrollIntoView({ behavior: "smooth", block: "center" });
    }
  }, 50);
}

export function getAppForm(form: {
  AppForm?: React.ComponentType<React.PropsWithChildren>;
}): React.ComponentType<React.PropsWithChildren> {
  const AppForm = form.AppForm;
  if (!AppForm) {
    throw new Error(
      "TanStack AutoForm formControl must be created with useAppForm " +
        "exported from @acp-autoform/react/tanstack-form.",
    );
  }
  return AppForm;
}

/**
 * Formats an array of path segments into a TanStack Form compatible string path.
 * e.g., ["guests", "0", "name"] -> "guests[0].name"
 */
export function formatTanStackPath(path: string[]): string {
  return path.reduce((acc, part) => {
    if (!isNaN(Number(part))) {
      return `${acc}[${part}]`;
    }
    return acc ? `${acc}.${part}` : part;
  }, "");
}

export function getErrorMessage(fieldApi: any): string | undefined {
  const error = fieldApi.state.meta.errors?.[0];
  if (!error) return undefined;
  if (typeof error === "string") return error;
  if (typeof error.message === "string") return error.message;
  return String(error);
}

/**
 * Wraps the form submit handler to stop event propagation.
 */
export const preventPropagation =
  (callback: (e: React.FormEvent<HTMLFormElement>) => void | Promise<void>) =>
  async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    e.stopPropagation();
    await callback(e);
  };
